import React, { useState, useEffect } from 'react';

function App() {
  const [produtos, setProdutos] = useState([]);

  // Aqui é onde eu  busco os dados do meu Backend (Porta 3001)
  useEffect(() => {
    fetch("http://localhost:3001/produtos")
      .then(res => res.json())
      .then(dados => setProdutos(dados))
      .catch(err => console.error("Erro ao carregar:", err));
  }, []);

  return (
    <div className="App">
      <h1>🛒 Supermercado Pollyanna</h1>

      {/* --- informações --- */}
      <div className="grid-produtos">
        {produtos.map((item) => (
          <div key={item.id} className="card">
            <img src={item.imagem_url} alt={item.produto} width="150" />
            <h3>{item.produto}</h3>
            <span className="categoria">{item.secao}</span>
            <p className="preco">R$ {parseFloat(item.valor).toFixed(2)}</p>
            <div className="estoque-info">
              <small>Disponível: <strong>{item.estoque}</strong> unidades</small>
            </div>
            {item.estoque < 50 && (
              <p style={{ color: 'red', fontSize: '12px' }}>⚠️ Estoque Baixo!</p>
            )}
          </div>
        ))}
      </div>
      {/* --------------------------- */}

    </div>
  );
}

export default App;
